#include<bits/stdc++.h>
using namespace std;
const int N = 1e6+5;
struct QRY{int ij,l,r,ans;}q[N];
int n,m,now,a[N],c[N],id[N];
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void write(int x){
    if(x>9)write(x/10);
    putchar(x%10+'0');
}
bool cmp1(QRY q1,QRY q2){return q1.r<q2.r;}
bool cmp2(QRY q1,QRY q2){return q1.ij<q2.ij;}
void add(int x,int k){
    while(x<=n){
        c[x]+=k;
        x+=(x&-x);
    }
    return;
}
int ask(int x){
    int sum=0;
    while(x){
        sum+=c[x];
        x-=(x&-x);
    }
    return sum;
}
int main(){
    n=read();
    for(int i=1;i<=n;i++)a[i]=read();
    m=read();
    for(int i=1;i<=m;i++){
        cin>>q[i].l>>q[i].r;q[i].ij=i;
    }
    sort(q+1,q+m+1,cmp1);
    now=1;
    for(int i=1;i<=n;i++){
        if(id[a[i]])add(id[a[i]],-1);
        id[a[i]]=i,add(i,1);
        while(now<=m&&q[now].r<=i)
            q[now].ans=ask(q[now].r)-ask(q[now].l-1),now++;
    }
    sort(q+1,q+m+1,cmp2);
    for(int i=1;i<=m;i++)cout<<q[i].ans<<"\n";
    return 0;
}
